    // ============================================================================
    // Guard-vs-insertion pattern: guards must check an ancestor of the insertion
    // point, never the element itself when insertion is .after() (sibling).
    // Violation causes infinite duplication via MutationObserver re-runs.
    // ============================================================================

    ackTest('addQuickCommentActions guard cleans up stale actions before re-adding', () => {
        // Guard: checks header.dataset.ackQuickProcessed === editState && staleActions.length === 1
        // Stale cleanup: staleActions.forEach(el => el.remove()) prevents duplicates
        // Insert: badgesGroup.after(actionContainer) or header.appendChild(actionContainer)
        // Both are inside header subtree. CORRECT.
        const source = _ackSource;
        ackAssert(source.includes("staleActions.forEach(el => el.remove())"), 'removes stale actions');
        ackAssert(source.includes('badgesGroup.after(actionContainer)'), 'inserts relative to header child');
    });

    ackTest('quick action buttons use pointerdown to prevent race condition with GitHub re-renders', () => {
        const source = _ackSource;
        const start = source.indexOf('const makeIconBtn');
        const end = source.indexOf('for (const header of headers)', start);
        const makeIconSection = source.slice(start, end);
        ackAssert(makeIconSection.includes("'pointerdown'"), 'uses pointerdown event');
        ackAssert(makeIconSection.includes('handler(btn)'), 'invokes handler on pointerdown');
        // Allow a click listener ONLY for suppression (prevent submit / bubbling),
        // but never for invoking the action handler.
        ackAssert(!/addEventListener\('click'[\s\S]*handler\(/.test(makeIconSection),
            'does not invoke handler on click (would race with React re-renders)');
    });

