	    ackTest('observer helpers use qsa() for scoped queries', () => {
	        const source = _ackSource;
	        const nextTopLevelFunctionIdx = (fromIdx) => {
	            // Find the next top-level-ish function definition (async or not).
	            // This is intentionally heuristic (string-based tests) but avoids
	            // false positives when `async function` appears between two normal
	            // `function` declarations (which previously caused unrelated code
	            // to be counted as part of the prior function).
	            const re = /\n[ \t]*(?:async\s+)?function\s+[A-Za-z0-9_$]+\s*\(/g;
	            re.lastIndex = Math.max(0, fromIdx);
	            const m = re.exec(source);
	            return m ? m.index : -1;
	        };
	        // Check across all scoped functions (they're spread across the file)
	        const fnNames = ['prefillCommitHash', 'addQuickCommentActions', 'addDetailsButtons', 'addStartReviewButtons',
	            'autoOpenReactionPopup', 'expandReactionAvatars', 'makeStickyEditToolbar'];
	        let totalQsa = 0;
        let totalDocScan = 0;
	        for (const fn of fnNames) {
	            const start = source.indexOf(`function ${fn}(root`);
	            const nextFn = nextTopLevelFunctionIdx(start + 1);
	            const section = source.slice(start, nextFn > start ? nextFn : start + 1200);
	            totalQsa += (section.match(/qsa\(root,/g) || []).length;
	            totalDocScan += (section.match(/document\.querySelectorAll/g) || []).length;
	        }
	        ackAssert(totalQsa >= 7, `expected at least 7 qsa(root, ...) calls, found ${totalQsa}`);
        ackAssert(totalDocScan <= 1, `expected at most 1 document.querySelectorAll in scoped functions (overlay search ok), found ${totalDocScan}`);
    });

