	    ackTest('addQuickCommentActions detects mine via octolytics-actor-login fallback', () => {
	        const root = document.createElement('div');
	        root.id = 'acktest-qactions-octo';
        Object.assign(root.style, {position: 'absolute', left: '-10000px', top: '0', width: '400px'});

        const container = document.createElement('div');
        container.className = 'timeline-comment';

        const header = document.createElement('div');
        header.className = 'timeline-comment-header';

        const flex = document.createElement('div');
        flex.className = 'd-flex flex-row-reverse';
        const actions = document.createElement('div');
        actions.className = 'timeline-comment-actions';
        const badges = document.createElement('div');
        badges.className = 'd-none d-sm-flex';
        flex.appendChild(actions);
        flex.appendChild(badges);
        header.appendChild(flex);

        const author = document.createElement('a');
        author.setAttribute('data-hovercard-type', 'user');
        author.setAttribute('href', '/acktest_user');
        header.appendChild(author);

        container.appendChild(header);
        root.appendChild(container);
        document.body.appendChild(root);

        const created = [];
        const metaUserExisting = document.querySelector('meta[name="user-login"]');
        const metaActorExisting = document.querySelector('meta[name="octolytics-actor-login"]');
        const oldUser = metaUserExisting?.getAttribute('content');
        const oldActor = metaActorExisting?.getAttribute('content');
        const ensureMeta = (name) => {
            let m = document.querySelector(`meta[name="${name}"]`);
            if (!m) {
                m = document.createElement('meta');
                m.setAttribute('name', name);
                document.head.appendChild(m);
                created.push(m);
            }
            return m;
        };

        try {
            // Force fallback to octolytics-actor-login by setting user-login to '' (falsy).
            ensureMeta('user-login').setAttribute('content', '');
            ensureMeta('octolytics-actor-login').setAttribute('content', 'acktest_user');

            addQuickCommentActions(root);
            const qa = header.querySelector('.ack-quick-actions');
            ackAssert(qa, 'missing .ack-quick-actions');
            ackAssert(qa.querySelector('button[title="Edit comment"]'), 'missing edit button');
        } finally {
            // Restore original meta contents (or remove if we created them).
            if (metaUserExisting) metaUserExisting.setAttribute('content', oldUser ?? '');
            if (metaActorExisting) metaActorExisting.setAttribute('content', oldActor ?? '');
            created.forEach(m => m.remove());
            root.remove();
        }
    });

