    ackTest('callLLM prompt cache respects cacheEnabled setting', async () => {
        const origReq = GM_xmlhttpRequest;
        const origParsePageContext = parsePageContext;
        const origPageKind = pageKind;
        let networkCalls = 0;
        try {
            parsePageContext = () => ({owner: 'bitcoin', repo: 'bitcoin', pr: '123'});
            pageKind = () => 'pull';
            GM_setValue('llm_claude_key', 'test-key');
            GM_setValue('llm_cache_enabled', false);
            const promptKey = buildPromptCacheKey('claude', LLM_MODELS.claude, 'system prompt', 'user prompt');
            ackAssert(!!promptKey, 'prompt key should be generated for cacheEnabled test');
            GM_setValue(promptKey, 'cached-response');

            GM_xmlhttpRequest = ({onload}) => {
                networkCalls++;
                const payload = {
                    content: [{text: 'live-response'}],
                    usage: {input_tokens: 1, output_tokens: 1},
                };
                onload?.({status: 200, responseText: JSON.stringify(payload)});
            };

            const result = await callLLM('claude', 'system prompt', 'user prompt');
            ackEq(result, 'live-response', 'cache disabled should not return cached value');
            ackEq(networkCalls, 1, 'cache disabled should still call network');
            ackEq(GM_getValue(promptKey, null), 'cached-response', 'cache disabled should not overwrite prompt cache key');
        } finally {
            GM_xmlhttpRequest = origReq;
            parsePageContext = origParsePageContext;
            pageKind = origPageKind;
        }
    });

