    ackTest('gatherCommentElements: issue pages include issue body + comments', () => {
        const host = document.createElement('div');
        host.style.position = 'absolute';
        host.style.left = '-99999px';
        host.innerHTML = `
          <div data-testid="issue-body">
            <a id="issue-1-permalink" href="#issue-1">permalink</a>
            <relative-time datetime="2026-03-01T00:00:00Z"></relative-time>
            <div data-testid="markdown-body" class="markdown-body"><p>Issue body text</p></div>
          </div>
          <div data-testid="issue-comment-2">
            <a id="issuecomment-2-permalink" href="#issuecomment-2">permalink</a>
            <relative-time datetime="2026-03-02T00:00:00Z"></relative-time>
            <div data-testid="markdown-body" class="markdown-body"><p>Issue comment text</p></div>
          </div>
        `;
        document.body.appendChild(host);

        const origQS = document.querySelectorAll;
        const origParsePR = parsePR;
        document.querySelectorAll = (sel) => {
            if (sel === MARKDOWN_BODY_SELECTOR) return host.querySelectorAll(sel);
            return [];
        };
        parsePR = () => null; // simulate issue page
        try {
            const entries = gatherCommentElements();
            ackEq(entries.length, 2, 'should find issue body + comment');
            ackEq(entries[0].el.getAttribute('data-testid'), 'issue-comment-2', 'newest is issue comment');
            ackEq(entries[1].el.getAttribute('data-testid'), 'issue-body', 'older issue body follows');
        } finally {
            document.querySelectorAll = origQS;
            parsePR = origParsePR;
            host.remove();
        }
    });

