    // --- callLLM cache key behavior ---

    ackTest('callLLM prompt cache key round-trip stores and reuses cached response', async () => {
        const origReq = GM_xmlhttpRequest;
        const origParsePageContext = parsePageContext;
        const origPageKind = pageKind;
        let networkCalls = 0;
        try {
            // Stabilize page context for deterministic prompt-key generation.
            parsePageContext = () => ({owner: 'bitcoin', repo: 'bitcoin', pr: '123'});
            pageKind = () => 'pull';
            GM_setValue('llm_claude_key', 'test-key');
            GM_setValue('llm_cache_enabled', true);
            GM_xmlhttpRequest = ({onload}) => {
                networkCalls++;
                const payload = {
                    content: [{text: 'cached-response'}],
                    usage: {input_tokens: 3, output_tokens: 5},
                };
                onload?.({status: 200, responseText: JSON.stringify(payload)});
            };

            const first = await callLLM('claude', 'system prompt', 'user prompt');
            const second = await callLLM('claude', 'system prompt', 'user prompt');
            ackEq(first, 'cached-response', 'first call should parse provider response');
            ackEq(second, 'cached-response', 'second call should return identical cached text');
            ackEq(networkCalls, 1, 'second call should hit prompt cache and avoid network');

            const key = buildPromptCacheKey('claude', LLM_MODELS.claude, 'system prompt', 'user prompt');
            ackAssert(!!key, 'prompt cache key should be generated for PR context');
            ackEq(GM_getValue(key, null), 'cached-response', 'cache value should be stored under buildPromptCacheKey key');
        } finally {
            GM_xmlhttpRequest = origReq;
            parsePageContext = origParsePageContext;
            pageKind = origPageKind;
        }
    });

    ackTest('callLLM skipCache ignores prompt cache and does not mutate cached value', async () => {
        const origReq = GM_xmlhttpRequest;
        const origParsePageContext = parsePageContext;
        const origPageKind = pageKind;
        let networkCalls = 0;
        try {
            parsePageContext = () => ({owner: 'bitcoin', repo: 'bitcoin', pr: '123'});
            pageKind = () => 'pull';
            GM_setValue('llm_claude_key', 'test-key');
            GM_setValue('llm_cache_enabled', true);
            const promptKey = buildPromptCacheKey('claude', LLM_MODELS.claude, 'system prompt', 'user prompt');
            ackAssert(!!promptKey, 'prompt key should be available for skipCache test');
            GM_setValue(promptKey, 'stale-cache-value');

            GM_xmlhttpRequest = ({onload}) => {
                networkCalls++;
                const payload = {
                    content: [{text: 'live-response'}],
                    usage: {input_tokens: 1, output_tokens: 1},
                };
                onload?.({status: 200, responseText: JSON.stringify(payload)});
            };

            const result = await callLLM('claude', 'system prompt', 'user prompt', {skipCache: true});
            ackEq(result, 'live-response', 'skipCache should return live provider response');
            ackEq(networkCalls, 1, 'skipCache should force exactly one network request');
            ackEq(GM_getValue(promptKey, null), 'stale-cache-value', 'skipCache should not overwrite cached prompt value');
        } finally {
            GM_xmlhttpRequest = origReq;
            parsePageContext = origParsePageContext;
            pageKind = origPageKind;
        }
    });

